type Profile_Data is record
   Set : Restriction_Flags;
   Value : Restriction_Values;
end record;

type Restrictions_Info is record
   Set : Restriction_Flags;
   Value : Restriction_Values;
   Violated : Restriction_Flags;
   Count : Restriction_Values;
   Unknown : Parameter_Flags;
end record;

